INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (231, 'single', '大數據（Big Data）資料來源種類包羅萬象，最簡單分類為結構化與非結 構化。非結構化資料從早期的文字資料類型，已擴展到網路影片、視訊、 音樂、圖片等，複雜的非結構化資料類型造成儲存、探勘、分析的困難。 這樣的特性指的是？', 'Volume,Velocity,Variety,Value ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (232, 'single', '大數據（Big Data）分析中的”大量數據”，指的是哪個特性？', 'Volume,Velocity,Variety,Veracity ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (233, 'single', '大數據（Big Data）分析的標的來源為何？', '原始數據（Raw Data）,依 據統計理論取樣本,隨機取夠多樣本即可,分類取樣本 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (234, 'single', '大數據（Big Data）對於即時性的資料可以快速加入分析，這特性指的 是？', 'Volume,Velocity,Variety,Veracity ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (235, 'single', '大數據（Big Data）分析方式中，最能夠直觀呈現大數據特點的方法是？', '可視化分析（Visibility Analysis）,資料探勘（Data Mining）,資料 管理分析（Data Management Analysis）,預測性分析（Predictive Analysis） ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (236, 'single', '大數據（Big Data）分析因為採用原始數據（Raw Data）處理，常常會發 現以前因為科技所限制而忽略的資料，這類資料稱為', '千兆級資料（Peta data）,交互式資料（Interaction data）,灰色資料（Gray data）,暗資 料（Dark data） ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (237, 'single', '常用於大數據（Big Data）分析工具Hadoop 中的MapReduce 架構主要是 執行哪一項功能？', '運算處理（Process）,互動（Interaction）,儲存 （Store）,叢集（Cluster） ', '0', '');
