INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (250, 'single', '對於車載通訊發展之敘述，下列何者正確？', '應用電子、通信、資訊與感 測等技術，以整合人、路、車的管理策略,車載通訊用越多將致使交通越 惡化,提供定時批次（batch）資訊以增進運輸系統的安全、效率及舒適 性,車載通訊只運用於車輛內裝之科技通訊技術 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (251, 'single', '對於Bank 4.0 帶來的轉變，下列敘述何者正確？', '須增設更多實體人工 櫃台,大量運用大數據來分析顧客需求,全面撤除傳統線下（offline）實 體交易服務,提供更多服務人員處理銀行收付服務 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (252, 'single', '下列何者是Web 3.0 與Web 2.0 的差異？', '分享內容服務,社群互動服 務,語意解析服務,入口網站 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (253, 'single', 'Web 2.0 與Web 3.0 的比較，下列何者正確？', 'Web 2.0 強調個人的網路 世界，Web 3.0 則強調讀寫互動,Web 2.0 發展分享內容，Web 3.0 則發 展靜態內容,Web 2.0 分析使用者行為，Web 3.0 則以標籤、關鍵字分類,Web 2.0 發展部落格網路，Web 3.0 則發展語意化的網路 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (254, 'single', '有關智慧交通之敘述，下列何者正確？', '可以運用感測器與攝影機來即時 分析路況,未經使用者許可之下，仍蒐集行車裝置紀錄來分析路況,運 用車間通訊的主要目標是拉遠車輛間的距離,運用智慧交通誘導方式無法 降低塞車機率 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (255, 'single', 'IBM 於2009 年提出下列何種概念，可視為物聯網的雛型？', '行動地球,智慧地球,智慧城市,感知城市 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (256, 'single', '有關物聯網之敘述，下列何者正確？', '透過物聯網蒐集的少量資訊也能發 揮顯著價值,物聯網可賦予智慧給物件，並擁有與其他物件或人溝通的能 力,網路層主流關鍵技術包含雲端運算、巨量資料分析、資料探勘、商業 智慧（BI）,物聯網的英文名稱為Interconnection of Things（IoT） ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (257, 'single', '主動式標籤的特性為何？', '不需要電源就可主動回傳資料至讀取器,通 常需要裝配電池才可回傳資料至讀取器,主動回傳資料至讀取器是採用散 射技術,不會回傳資料至讀取器只能由讀取器自行讀取 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (258, 'single', 'ZigBee 在媒體存取層與實體層是採用下列何種標準協定？', 'IEEE 802.15.4,IEEE 802.11n,IEEE 802.3,IEEE 802.20 ', '0', '');
