INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (263, 'single', '歐洲電信標準協會（ETSI）將物聯網分為哪三個階層？', '感知層、網路 層、應用層,連結層、網路層、應用層,感知層、傳輸層、應用層,感 知層、網路層、連結層 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (264, 'single', '下列何者為物聯網的英文名稱？', 'Interconnection of Things,Internet of Things,Internet of Telecommunications,Interconnection of Telecommunications ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (265, 'single', '有關物聯網之敘述，下列何者正確？', '無須具備自我組織的能力,IPv4 可以滿足物聯網的所有技術需求,只能透過無線網路傳輸訊息,每個物 件要有可獨立定址的網路位址，以互聯互通 ', '3', '');
