INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (270, 'single', '下列何項資安威脅就是以密碼鎖住硬碟資料，讓使用者無法使用該資料？', '勒索軟體,DDOS 攻擊,XSS 攻擊,網路釣魚 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (271, 'single', '關於資訊安全之敘述，下列何者正確？', '資訊安全是資訊人員的事情，其 他人不用理會,資訊安全主要議題就是防毒軟體的選用,資訊安全是管 理議題，技術層面為輔助性議題,只要電腦安裝防毒軟體，就符合資訊安 全 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (272, 'single', '如何判斷這個資訊安不安全，從High Level 角度可以以何者來判斷？', 'CIA Triad,防火牆強度,資訊機密性強度,防毒軟體的評價 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (273, 'single', '資訊安全三要素CIA，其中C 指的是？', '機密性,完整性,可用性,可 鑑別性 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (274, 'single', '資訊安全三要素CIA，其中I 指的是？', '機密性,完整性,可用性,不 可否認性 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (275, 'single', '資訊安全三要素CIA，其中A 指的是？', '機密性,完整性,可用性,存 取權控制 ', '2', '');
