INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (278, 'single', '關於3A 認證協定，下列何項協定是目前使用率最高的協定？', 'RADIUS,TACACS,TACACS＋,HWTACACS ', '0', '');
