INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (280, 'single', '下列何項技術可有效阻擋跨網站腳本XSS（Cross-Site Scripting）的攻 擊？', '運用cookies 資料判斷網站安全性,禁用cookies,網頁內容安全 政策CSP（Content Security Policy）規範,只允許POST 機制 ', '2', '');
