INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (282, 'single', '對於公司而言，任何機密資訊未經授權前都無法被看到，是符合資訊安全 CIA 中的何項要素？', '機密性,完整性,可用性,可鑑別性 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (283, 'single', '下列何項攻擊是利用簡訊吸引受害者按下進入假網站？', '魚叉式網路釣魚 （Spear phishing）,網路捕鯨（Whaling）,複製型釣魚攻擊（Clone phishing）,網路釣魚簡訊和網路釣魚電話（Smishing and vishing） ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (284, 'single', '駭客偽造大量正常連接主機的用戶IP，並發送錯誤數據，迫使主機斷開與 這些IP 的連接，導致擁有這些IP 的用戶無法正常訪問主機。這類型攻擊 稱為？', 'IP Spoofing,DoS,Information Explosion,Reflection attack ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (285, 'single', '駭客發送大量帶有被害者IP 地址的數據包給攻擊主機，導致被攻擊主機對 IP 地址源做出大量回應，造成拒絕服務。這類型攻擊稱為？', 'XSS,SQL injection,DRDoS,IP Spoofing ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (286, 'single', '在資訊安全中，對一已發生之行動或事件的證明，使該行動或事件往後不 能被否認的能力，是屬於下列何種特性？', 'Access Control（存取權限控 制）,Non-repudiation（不可否認性）,Authentication（鑑別性）,Confidentiality（機密性） ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (287, 'single', '下列何種攻擊方式是採用TCP 三向交（Three Way Handshake）的漏洞進 行攻擊的？', 'XSS,DDoS,SQL injection,Phishing ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (288, 'single', '對於公司而言，應該要確保資料不被未授權的人修改，以及確保資料處理 的過程是安全且合規的是符合資訊安全CIA 中的何種要素？', '機密性,完整性,可用性,不可否認性 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (289, 'single', '下列何項攻擊是駭客透過修改SQL 語句，改變語意，達成竊取或破壞資料 的行為？', 'XSS,DDoS,SQL injection,Phishing ', '2', '');
