INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (293, 'single', '找尋專業可靠的公有雲服務、自建雲服務或建立混合雲服務是為解決資訊 安全五大威脅的何項威脅？', '網路安全,系統安全,應用程式安全,雲 端運算安全 ', '3', '');
