INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (349, 'single', '在Microsoft Word 環境中，若要以一個預先建置完成的通訊錄檔案來大量 製作信封上的郵寄標籤，下列何種製作方法最簡便？', '合併列印,範本,版面設定,表格 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (350, 'single', '若在Microsoft Word 環境中執行合併列印的動作時，由「插入合併欄位」 功能所插入的欄位變數名稱「地址」會被下列何種符號框起來？', '?地址?,{地址},[地址],«地址» ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (351, 'single', '有關Microsoft Word 之「欄」的敘述，下列何者錯誤？', '段落文字以欄 寬做為換行的基準,可對不同的節設定不同的欄格式,先選定部分文 字，再進行欄格式設定，Word 會在選定範圍前後位置插入分節符號,欄 格式的設定只在直書情況下進行，橫書則不可 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (352, 'single', '在Microsoft Word 之「檔案/列印」功能選項中，若只要列印第2 頁至第8 頁時，應在對話盒中之「頁面」方框中輸入？', '2~8,2-8,2,8,2:8 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (353, 'single', '若在Microsoft Word 環境中要使用二種不同格式的頁碼時，必須在不同頁 碼之文件中插入下列何種符號？', '分頁,分欄,分節,文字換行分 隔 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (354, 'single', '下列應用軟體中，何者不具有文書處理功能？', 'Microsoft Word,Microsoft Access,WordPad,OpenOffice Writer ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (355, 'single', '在Microsoft Word 之「檔案/另存新檔」功能選項中，無法將檔案儲存為 下列何種副檔名？', '.pdf,.dotx,.rtf,.pptx ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (356, 'single', '有關Microsoft Word 之「表格」的敘述，下列何者錯誤？', '表格內之數 字資料可以被運算,表格內之數字資料可以被排序,表格內不可以有圖 形,表格內之儲存格可以被分割或合併 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (357, 'single', '在Microsoft Word 之「版面配置」索引標籤內的「直書/橫書」功能選項 中，下列何種類型的資料無法達到「直書/橫書」的功能？', '繁體中文字,簡體中文字,半形英文字,全形英文字 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (358, 'single', '在Microsoft Word 的操作環境中，若要同時選取某一段文章的第二行第3 至第6 個字與第三行第3 至第6 個字，可先按下哪一個鍵，再將滑鼠移至 第二行第3 個字按住滑鼠，並拉動滑鼠至第三行第6 個字即可完成選取的 動作？', 'Ctrl 鍵,Alt 鍵,Shift 鍵,Tab 鍵 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (359, 'single', '有關Microsoft Word 之敘述，下列何者錯誤？', '若某一段落被設定為 「固定行高」且「行高12 點」，而此段落的中文字卻被設定為「大小24 點」，則文字的上半部不會顯示出來,可以將圖片插入在文件的頁首區域 內,具有「Web 版面配置」模式，可檢視文件的網頁外觀,建立表格時 最多只能設定48 個欄位 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (360, 'single', '有關Microsoft Word 之敘述，下列何者錯誤？', '無法為文字設定註解,可以改變檔案內容的顯示比例,可以製作具有多欄的檔案內容,可以使 用書籤快速跳至所定義的位置處 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (361, 'single', '在Microsoft Word 中，有關「索引標籤、群組」之敘述，下列何者錯誤？', '可新增索引標籤,可調整「檔案」索引標籤的位置,可隱藏預設的索 引標籤,不能隱藏預設的群組 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (362, 'single', '在Microsoft Word 中，下列何者不是「文字效果」所提供的效果？', '陰 影,反射,光暈,立體旋轉 ', '3', '');
