INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (401, 'single', '作業系統的主要功能為記憶體管理、處理機管理、設備管理及下列何項？', '資料管理,I/O 管理,中文管理,程式管理 ', '1', '');
