INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (403, 'single', '作業系統（Operating System）之主要目的，是為了幫助使用者更有效率及 更方便的使用電腦的硬體資源，下列何項不是一種作業系統的名稱？', 'Windows,Linux,PL/1,UNIX ', '2', '');
