INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (405, 'single', '下列敘述何者錯誤？', 'BCD 碼使用一組4 位元表示一個十進位制的數字,通用漢字標準交換碼為目前我國之國家標準交換碼,ASCII 碼為常用的 文數字資料的編碼,BIG-5 碼是中文的外碼 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (406, 'single', '在中文資料處理中，兩種不同資料之傳送過程必須靠下列何種碼來傳送？', '輸入碼,內碼,交換碼,輸出碼 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (407, 'single', '下列何者負責監督電腦系統工作？', '作業系統,套裝程式,應用程式,編譯程式 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (408, 'single', '對於 Windows 作業系統的「開始」鈕操作介面敘述，下列何者正確？', '只具有功能表,只具有動態磚功能,可以在「個人化」進行顯示應用程 式清單的設定,不能設定為全螢幕顯示 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (409, 'single', '在Linux 作業系統下，使用何種指令可以顯示目前的目錄？', 'makdir,fg,pwd,cat ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (410, 'single', '下列何種中文輸入法與拆碼無關？', '行列輸入法,手寫輸入法,大易輸 入法,倉頡輸入法 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (411, 'single', '在 Windows 作業系統的「命令提示字元」視窗中，下列敘述何者錯誤？', '根目錄（Root）也是一個目錄，而且不能被刪除,VER 指令用於顯示 Windows 版本,RMDIR 所欲刪除之目錄必須是個空目錄，否則將會拒絕 刪除,如果根目錄下沒有USR 這個子目錄（Subdirectory），就不能執行 MD\USR\ABC ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (412, 'single', '何者為Internet 的遠端登入（login）功能？', 'telnet,ping,cmd,crd ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (413, 'single', '數據機傳輸資料的速率之單位為何？', 'bps（bit per second）,Bps （Byte per second）,Mps（Mega per second）,Gps（Giga per second） ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (414, 'single', '「注音輸入法」是依照文字的什麼輸入？', '字形,字根,字義,字 音 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (415, 'single', '下列系統何者可幫助使用者管理硬體資源，使電腦發揮最大的效能？', '作 業系統,媒體,資料系統,編修系統 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (416, 'single', '下列敘述何者錯誤？', '程式執行、檔案存取等皆屬於作業系統服務範疇,COBOL 及BASIC 皆屬於作業系統軟體,電腦系統包含硬體、作業系 統、應用程式及使用者,作業系統目的是為了更方便和更有效率的使用電 腦 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (417, 'single', '下列何者符合程式多工處理（Multiprogramming）的工作原理？', '處理完 一件工作後，才處理下一件工作,電腦一次可以處理多個工作 （Process），但同一時段內只處理一件工作中的一部分,同時段內處理 所有工作的輸出入動作（I/O Operation）,電腦同時段內可處理多件工 作 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (418, 'single', '使用直譯器（Interpreter）將程式翻譯成機器語言的方式，下列敘述何者 正確？', '直譯器與編譯器（Compiler）翻譯方式一樣,先翻譯成目的碼 再執行之,在鍵入程式的同時，立即翻譯並執行,依行號順序，依序翻 譯並執行 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (419, 'single', '下列何者不屬於系統軟體？', '公用程式（Utility）,作業系統 （Operating System）,會計系統（Accounting System）,編譯程式 （Compiler） ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (420, 'single', '在安裝介面卡時，若PC 內已有其他介面卡，則應該注意I/O 位址、IRQ 及下列何項是否相衝突？', 'DMA,Baud Rate,Packet Size,Frame Size ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (421, 'single', '下列敘述何者正確？', '編譯器（Compiler）可編譯應用程式，故屬於應用 軟體,物流管理系統軟體屬於應用軟體,作業系統不能編譯程式，所以 不是系統軟體,作業系統（Operation System）可以編譯程式，所以屬於 系統軟體 ', '1', '');
