INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (506, 'single', '在Linux 作業系統中，/var/test 是一個擁有下層檔案及子資料夾的資料 夾，想要刪除/var/test 的指令為何？', 'del/var/test/*,rm -rf /var/test,del -Rf /var/test/*,rm -rf /var/test/* ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (507, 'single', '關於固態硬碟SSD（Solid State Disk）之敘述，下列何者錯誤？', '無須驅 動馬達、承軸或旋轉頭裝置，具有低耗電、低熱能的優點,比起傳統的標 準機械硬碟來說，SSD 所能承受的操作衝擊耐受度較高,採用DRAM 或 Flash 取代傳統硬碟的碟片，讀寫速度快,SSD 資料儲存密度高，故價格/ 每單位儲存容量也比傳統硬碟便宜 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (508, 'single', '關於XML（eXtensible Markup Language）之敘述，下列何者錯誤？', 'XML 提供一個跨平台、跨網路、跨程式語言的資料描述格式,XML 和 HTML 一樣，都只能使用事先定義的標籤（tag）,DTD 是用來規範XML 文件的格式,XSL 用來提供XML 套用排版樣式之功能 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (509, 'single', '下列何者是使得Java 程式能夠完成跨平台（cross platform）運作的主要機 制？', '例外處理,多執行緒（multi-thread）,虛擬機器,物件導向 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (510, 'single', '下列有關作業系統的操作中，何者是不需要使用系統呼叫（system call）？', '計算費伯納西數列（Fibonacci sequence）,刪除一個行程 （kill process）,開啟一個檔案（open file）,在螢幕上印出一些文字 （screen output） ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (511, 'single', '有關資料傳輸的介面，根據官方所公布的規格，下列何者傳輸速度最快？', 'SATA3,eSATA,USB3.0,IEEE 1394b ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (512, 'single', '有關「雲端運算」技術概念之敘述，下列何者正確？', '在電腦上進行雲狀 式的數學運算,空軍在雲層中利用電腦進行運算,兩台電腦以藍芽互相 傳送機密性資料,透過網路連線取得遠端主機提供的服務 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (513, 'single', '下列何者的傳輸媒介不是使用光纖？', '1000BaseT,1000BaseSX,FDDI,10BaseF ', '0', '');
