INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (520, 'single', 'IPv4 中提供使用私有IP 位址空間的網路，例如192.168.0.0- 192.168.255.255 的區塊，下列何者是IPv6 私有IP 位址空間的寫法？', 'FE80::1,FEC0::2,FF02::A001,FF02::1:FF00:0101:0202 ', '1', '');
