INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (566, 'single', '在 Windows 作業系統中，若已經同時執行多個程式，但想透過按鍵方式來 選擇其中某一個程式成為使用中應用程式，下列何者操作正確？', '先按住 Ctrl 鍵，再利用Tab 鍵來依序切換到所要的應用程式,先按住Alt 鍵，再 利用Tab 鍵來依序切換到所要的應用程式,先按住Tab 鍵，再利用Ctrl 鍵來依序切換到所要的應用程式,先按住Tab 鍵，再利用Alt 鍵來依序切 換到所要的應用程式 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (567, 'single', '若在 Windows 作業系統開啟5 個應用程式，且要各自使用不同的輸入 法，下列敘述何者正確？', '無法做到,最多只能使用2 種輸入法,最多 可使用4 種輸入法,可達成使用5 種輸入法 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (568, 'single', '在 Windows 作業系統中，若在「本機」圖示上按滑鼠右鍵，並選取快顯功 能表中的「內容」選項，則會出現下列何種項目？', '關於,儲存體,顯 示器,音效 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (569, 'single', '在 Windows 作業系統中，「步驟收錄程式」預設是以下列何種形式記錄操 作步驟？', '文字,截圖,影片,文字及截圖 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (570, 'single', '在 Windows 作業系統中，想要擷取螢幕畫面上的某一區域，下列何者正 確？', '同時按下Alt＋PrtSc 鍵,可使用內建的「剪取工具」,一定要另 外購買安裝畫面擷取應用程式,於所要擷取區域按滑鼠右鍵，並選取快顯 功能表中的「複製」選項 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (571, 'single', '在 Windows 作業系統中，在印表機的「印表機內容」選擇「連接埠」，下 列何者不會出現於連接埠選單？', 'LPT1:,FILE:,PS/2:,COM1: ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (572, 'single', '在登入Windows 作業系統時，所輸入密碼的大小寫與原設定不符，會有下 列何種結果？', '可正常登入作業系統,以安全模式登入作業系統,要求 重新輸入密碼,關閉作業系統並重新開機 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (573, 'single', '在Windows 作業系統中，下列何種操作可保留原帳號使用者之工作內容， 且可切換到另一個使用者帳號？', '登入,切換使用者,登出,重新啟 動 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (574, 'single', '在Windows 作業系統中，檔案屬性不包含下列何者？', '唯讀,隱藏,共 享,系統 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (575, 'single', '有關 Windows 作業系統中「檔案總管」之敘述，下列何者錯誤？', '具有 檔案複製功能,可設定檔案檢視模式,具有搜尋功能,具有分割硬碟磁 區功能 ', '3', '');
