INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (577, 'single', '有關 Windows 「造字程式」之敘述，下列何者正確？', '可指定與現有輸 入法連結,無法匯入點陣字型檔,只能設定使用UNICODE 字碼,無法 造出向量字型 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (578, 'single', '若要利用Windows 連接上Internet，則必須設定下列何種網路通訊協定？', 'IPX/SPX,NetBUEI,TCP/IP,DLC ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (579, 'single', '在 Windows 作業系統中，若在桌面的空白區域按滑鼠右鍵，並選取快顯功 能表的「個人化」選項，則會開啟下列何種項目？', '語言,滑鼠,背景,顯示器 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (580, 'single', '在Windows 作業系統中，若設定資料夾為共享，且限定允許可檢視但不可 變更檔案資料，則使用權限應設定為下列何者？', '完全控制,變更,讀 取,讀取/寫入 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (581, 'single', '在 Windows 作業系統之「Windows 系統管理工具」中，不具備下列何種 功能？', '系統資訊,磁碟清理,工作管理員,重組並最佳化磁碟機 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (582, 'single', '在 Windows 作業系統中，若要變更開始功能表的設定，則須在「設定」視 窗中選取下列何者？', '個人化,更新與安全性,系統,應用程式 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (583, 'single', '在 Windows 作業系統中，若按一下滑鼠左鍵，卻出現快顯功能表，其可能 原因為下列何者？', '滑鼠故障,在「設定/裝置/滑鼠」之「選取主要按 鈕」被設定為「右」,滑鼠的驅動程式設定有誤,開啟觸控螢幕時，觸 控點周圍顯示視覺回饋 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (584, 'single', '在 Windows 作業系統中，若因經常進行複製及刪除檔案，造成檔案存取效 率不佳，則可執行下列何種程式來提升效能？', '磁碟壓縮程式,磁碟掃 描工具,重組並最佳化磁碟機,病毒掃描程式 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (585, 'single', '在 Windows 作業系統之「命令提示字元」，下列哪一對指令之功能不相 同？', 'CHDIR 與CD,MKDIR 與MD,RENAME 與REN,VERIFY 與 VER ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (586, 'single', '在Windows 作業系統的「命令提示字元」視窗中，下達「COPY C:\TEST.ABC D:\*.TXT」指令後，下列敘述何者正確？', 'D 磁碟會產生 檔名為TEST.ABC 的檔案,C 磁碟檔名為TEST.ABC 的檔案將會不存在,D 磁碟會產生檔名為TEST.TXT 的檔案,C 磁碟會產生檔名為 TEST.TXT 的檔案 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (587, 'single', '在 Windows 作業系統之「命令提示字元」，下列何者不是可執行檔的副檔 名？', 'bat,exe,com,prg ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (588, 'single', '在 Windows 作業系統之「命令提示字元」，若使用DEL 命令刪除某個檔 案時，螢幕出現「存取被拒」訊息，則表示此要被刪除檔案的屬性包含下 列何者？', '共享（Shared）檔案,系統（System）檔案,隱藏 （Hidden）檔案,唯讀（Read-Only）檔案 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (589, 'single', '在Windows 作業系統中，若執行「開始」功能表的「登出」選項，則會執 行下列何種動作？', '關閉Windows,重新啟動Windows,可讓新使用者 登入,讓電腦暫停運作進入省電模式 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (590, 'single', '在 Windows 作業系統中，下列何者不是「微軟注音」輸入法內定的鍵盤排 列方式？', '標準,倚天,IBM,王安 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (591, 'single', '在Windows 作業系統中，「Windows Media Player」無法播放下列何種格 式的檔案？', 'AVI,WAV,RMVB,MID ', '2', '');
