INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (595, 'single', '在 Windows 作業系統中，「Windows Media Player」不具備下列何種功 能？', '擷取音樂,播放音樂CD,轉錄成MP4 檔案,觀看網路電視的串 流視訊 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (596, 'single', '在 Windows 作業系統中，若要在桌面新增「本機」圖示，可於桌面的空白 處按滑鼠右鍵，選取快顯功能表的「個人化」選項，並需在下列何種項目 下進行設定？', '背景,色彩,鎖定畫面,佈景主題 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (597, 'single', '在Windows 作業系統中，可使用下列何種程式讓使用者登入時，自動執行 所指定的程式？', '資源監視器,工作排程器,執行,同步中心 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (598, 'single', '在 Windows 作業系統中，「Windows Defender」的功能為何？', '變更此 電腦的佈景主題,變更使用者帳戶設定和密碼,檢查是否有軟體及驅動 程式更新,協助保護您的電腦不受「惡意程式」的攻擊 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (599, 'single', '在 Windows 作業系統中，從何處可以還原已被刪除的檔案？', '控制台,資源回收筒,我的文件,系統還原 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (600, 'single', '在 Windows 作業系統中，「小畫家」所編輯的內容預設儲存成何種格式的 檔案？', '.jpeg,.gif,.bmp,.png ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (601, 'single', '在 Windows 作業系統中，使用下列何者可檢視電腦硬體狀態？', '裝置管 理員,使用者帳戶,地區及語言選項,協助工具選項 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (602, 'single', '在 Windows 作業系統之「檔案總管」，使用下列何種功能鍵可以更改檔案 或資料夾的名稱？', 'F1,F2,F3,F4 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (603, 'single', '在 Windows 作業系統中，下列何者功能不包含於「記事本」？', '更改字 型大小,變換字型,字型樣式為粗體,選擇文字顏色 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (604, 'single', '在 Windows 作業系統中，關於「帳戶」之說明，下列何者錯誤？', '一台 電腦中可建立多個使用者帳戶,使用者帳戶不一定要設密碼,建立密碼 可防止電腦病毒入侵,電腦系統管理員有權限刪除其它使用者帳戶 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (605, 'single', '使用下列何者可將已安裝之應用程式從電腦中移除？', '使用設定之「應用 程式」,清理資源回收筒,在桌面上刪除捷徑,從開始畫面取消釘選 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (606, 'single', '在 Windows 作業系統中，一個新的硬碟須做下列何項工作才能開始使用？', '初始化,系統化,格式化,清除化 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (607, 'single', '在Windows 作業系統中，若要以滑鼠選取連續多個檔案，滑鼠先點選第一 個檔案後，再按住下列何鍵，並用滑鼠點選要選取的最後一個檔案？', 'Ctrl,Shift,Alt,Tab ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (608, 'single', '在 Windows 作業系統中，「檔案總管」以何種檢視狀態呈現，可同時顯示 所有磁碟容量的大小？', '小圖示,大圖示,詳細資料,清單 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (609, 'single', '在 Windows 作業系統中，有關使用「命令提示字元」查看目錄資訊之敘 述，下列何者錯誤？', '「\」代表根目錄,「..」代表上一層,「C:\」代 表C 硬碟根目錄,「.」代表下一層 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (610, 'single', '在 Windows 作業系統中，「資源回收筒」最大容量為何？', '10MB,依 磁碟容量固定百分比,依磁碟容量等級固定大小,依磁碟容量可自訂大 小 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (611, 'single', '在 Windows 作業系統中，使用一段時間後儲存大檔案效率逐漸變差，為改 善效率，適合針對原磁碟機作下列何項合理處理？', '重組並最佳化磁碟機,修護磁碟機,磁碟清理,磁碟檢查錯誤 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (612, 'single', '下列何種作業系統最大的特點是開放原始程式碼給所有使用者？', 'Linux,Windows,macOS X,iOS ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (613, 'single', '在 Windows 作業系統時，若尚未進入Windows 作業系統之前，按下列何 種功能鍵，可以選擇進入安全模式？', 'F4,F8,F10,F12 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (614, 'single', '在 Windows 作業系統中，內建何種多媒體播放工具，可以進行播放音樂 CD 及DVD 影音檔案的功能？', 'iTunes,Power DVD,iKala,Windows Media Player ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (615, 'single', '下列敘述何者正確？', 'Linux 作業系統不支援TCP/IP 通訊協定，因此無 法用來架設網站,在 Windows 作業系統中，滑鼠左右鍵的用法已經固 定，不可以被修改,在 Windows 作業系統中，能夠同時播放.mid 與.wav 檔的音效,「多媒體電腦」是指電腦同時應用到多個新聞媒體的採訪報 導 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (616, 'single', '在 Windows 作業系統中，內建可觀賞和錄製電視節目軟體為何？', '遠端 桌面連線,Windows Movie Maker,Windows Media Player,Windows Media Center ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (617, 'single', '有關UNIX 作業系統之基本指令敘述，下列何者正確？', 'cd 用於顯示目 錄內容,ls 用於查詢工作目錄,chmod 用於改變檔案許可權,man 用於 顯示現在目錄的路徑 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (618, 'single', '下列何者不是 Windows 作業系統之桌面背景圖片可使用的檔案類型？', '.bmp,.gif,.jpg,.dwg ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (619, 'single', '有關UNIX 作業系統之敘述，下列何者錯誤？', 'cd 用於查詢工作目錄,檔名大小寫是相異的,mkdir 用於建立目錄,vi 為該作業系統最常見的文 字編輯器 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (620, 'single', 'UNIX 和 Windows 作業系統之比較敘述，下列何者錯誤？', 'UNIX 廣泛使 用於企業伺服器中，Windows 用於個人電腦,Windows 會分辨指令的英 文字母大小寫，UNIX 不會分辨,關於日誌式的檔案系統，Windows 只支 援 NTFS，UNIX 可以支援多種檔案系統,Windows 以副檔名分類檔案類 型，UNIX 則無此規則 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (621, 'single', '在作業系統中進行檔案複製或刪除，屬於下列何種程序？', '程序管理,檔案管理,網路管理,資源管理 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (622, 'single', '有關微軟Windows 作業系統之敘述，下列何者錯誤？', 'Windows Server 支援多人多工,Windows 為伺服器作業系統,Windows 可用於PC 及NB,具分配管理電腦資源的功能 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (623, 'single', '下列何種作業系統不支援多點觸控？', 'macOS,Ubuntu,Android,MS DOS ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (624, 'single', '在作業系統中刪除系統檔案時，會立即跳出警告訊息，這是屬於何種類型 的管理程序？', '資源管理,檔案管理,程序管理,錯誤偵測 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (625, 'single', '有關 Windows 作業系統之敘述，下列何者錯誤？', '可管理主記憶體,提 供程式執行環境，並可控制程式執行,具GUI 及文字介面,屬於單工作 業系統 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (626, 'single', '有關Windows 作業系統之操作敘述，下列何者正確？', '透過Ctrl＋Alt＋ Delete 組合鍵可選擇工作管理員,隨身碟位置一定在磁碟C 槽,Windows 之系統資料一定在磁碟D 槽,透過Ctrl＋Shift 組合鍵可選擇 「開始」功能表 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (627, 'single', '有關Linux 作業系統之敘述，下列何者錯誤？', '屬於自由軟體,可支援 多人多工作業環境,只有文字命令介面,屬於開放原始碼 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (628, 'single', '下列何者不是Windows 作業系統中「工作管理員」的功能？', '查詢整體 CPU 使用率,顯示應用程式使用記憶體狀態,顯示驅動程式的版本,結 束執行中的應用程式 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (629, 'single', '有關作業系統之敘述，下列何者錯誤？', 'Windows 是由Microsoft 所開發,iOS 是由Apple 所開發的智慧型手機作業系統,Android 不支援多點觸 控功能,Android 是以Linux 為基礎開發而成 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (630, 'single', '下列何者不屬於系統軟體？', '作業系統,編譯器,直譯器,資料庫軟 體 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (631, 'single', '在Windows 作業系統中，下列何種按鍵方式可擷取工作中視窗畫面？', 'PrintScreen,Alt＋PrintScreen,Ctrl＋PrintScreen,Alt＋Ctrl＋ PrintScreen ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (632, 'single', '下列何者為預防電腦犯罪最應做之事項？', '資料備份,建立資訊安全管 制系統,維修電腦,和警局連線 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (633, 'single', '關於「防治天然災害威脅資訊安全措施」，下列何者不適宜？', '設置防災 監視中心,經常清潔不用除濕,設置不斷電設備,設置空調設備 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (634, 'single', '下列何者不屬於資訊安全的威脅？', '天然災害,人為過失,存取控制,機件故障 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (635, 'single', '下列何者屬於惡意破壞？', '人為怠慢,擅改資料內容,系統軟體有誤,系統操作錯誤 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (636, 'single', '在資訊安全的種類中，有關媒體出入管制項目，是屬於下列何者的重要項 目之一？', '實體安全,資料安全,程式安全,系統安全 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (637, 'single', '下列哪一項為解決勒索病毒最根本的方法？', '安裝防毒軟體,定期離線 備份成不同版本,使用合法軟體,使用異地線上即時同步備援 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (638, 'single', '電腦病毒的侵入是屬於？', '機件故障,天然災害,惡意破壞,人為過 失 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (639, 'single', '使用同步式雲端儲存服務，下列哪一項可以有效解決勒索病毒？', '檔案在 本地端儲存時即上傳雲端儲存,雲端設置自動資料複本功能，有任何更新 即複製到遠端另一台儲存設備,版本控制,雲端儲存裝置加裝防毒軟 體 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (640, 'single', '「減少因系統元件當機的影響」是屬於？', '變更管理,能量管理,復原 管理,績效管理 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (641, 'single', '災變復原計劃，不包括下列何者之參與？', '程式設計人員,非組織內之 使用人員,系統操作人員,資料處理人員 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (642, 'single', '資料備份的常見做法為尋找第二安全儲存空間，其作法不包括？', '尋求專 業儲存公司合作,存放另一堅固建築物內,儲存在同一部電腦上,使用 防火保險櫃 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (643, 'single', '災害復原階段，首要的工作為何？', '軟體的重置,環境的重置,系統的 重置,資料的重置 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (644, 'single', '為了防止資料庫遭破壞後無法回復，除了定期備份外，尚須做下列哪一件 事？', '管制使用,人工記錄,隨時記錄變動日誌（Log）檔,程式修 改 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (645, 'single', '下列何者不是資訊系統安全之措施？', '備份（Backup）,稽核（Audit）,測試（Testing）,識別（Identification） ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (646, 'single', '下列哪一項不屬於區塊鏈技術可以達到的安全效果？', '運用時間戳記來記 錄交易,以資料切割分開存放在不同主機,使用橢圓曲線法來進行複雜 加密處理,將資料建成鏈狀，再以雜湊來建構資料集與資料集之關鏈 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (647, 'single', '下列何者是錯誤的「系統安全」措施？', '加密保護機密資料,系統管理 者統一保管使用者密碼,使用者不定期更改密碼,網路公用檔案設定成 「唯讀」 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (648, 'single', '下列何者是錯誤的「保護資料」措施？', '機密檔案由專人保管,資料檔 案與備份檔案保存在同磁碟機,定期備份資料庫,留下重要資料的使用 紀錄 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (649, 'single', '下列何者是錯誤的「電腦設備」管理辦法？', '所有設備專人管理,定期 保養設備,允許使用者因個人方便隨意搬移設備,使用電源穩壓器 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (650, 'single', '下列哪一項無法有效避免電腦災害發生後的資料安全防護？', '經常對磁碟 作格式化動作（Format）,經常備份磁碟資料,在執行程式過程中，重 要資料分別存在硬碟及碟片上,備份檔案存放於不同地點 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (651, 'single', '下列哪一項動作進行時，重新開機會造成檔案被破壞的可能性？', '程式正 在計算,程式等待使用者輸入資料,程式從磁碟讀取資料,程式正在對 磁碟寫資料 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (652, 'single', '若某公司內部存在100 名員工、50 部個人電腦、20 部印表機、且運作時 須特定軟體「Windows」方可運作，則至少應採購幾套此一特定軟體的授 權？', '20 套,1 套,100 套,50 套 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (653, 'single', '身分證字號的最後一碼是用來做為下列哪一種檢驗？', '範圍,總數,檢 查號碼的正確性,一致性 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (654, 'single', '確保電腦電源穩定的裝置是？', '保護設備,網路系統,空調系統,不斷 電系統 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (655, 'single', '下列何者不屬於保護電腦資料的安全措施？', '工作人員意外險,電路安 全系統,投保產物險,消防設施 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (656, 'single', '「電腦機房設置空調」的目的為下列何者？', '避免機房空氣污染,避免 電腦及附屬設備過熱,提供參觀的來賓使用,提供工作人員使用 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (657, 'single', '對電腦犯罪之敘述，下列何者錯誤？', '犯罪容易察覺,採用手法較隱藏,高技術性的犯罪活動,與一般傳統犯罪活動不同 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (658, 'single', '網路系統中資料安全的第一道保護措施為何？', '使用者密碼,目錄名稱,使用者帳號,檔案屬性 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (659, 'single', '為了避免電腦中重要資料意外被刪除，我們應該？', '嚴禁他人使用該部電 腦,安裝保全系統,將資料內容全部列印為報表,定期備份 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (660, 'single', '為了避免文字檔案被任何人讀出，可進行加密（Encrypt）的動作。在加密 時一般是給予該檔案？', '存檔的空間,個人所有權,Key,Userid ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (661, 'single', '在電腦術語中常用的「UPS」，其主要功能為何？', '消除靜電,傳送資料,防止電源中斷,備份資料 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (662, 'single', '對於「防範電腦犯罪的措施」中，下列何者不正確？', '避免採用開放系統 架構,加強門禁管制,資料檔案加密,明確劃分使用者權限 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (663, 'single', '下列何種類型的資訊安全威脅最難預防？', '人為疏失,機械故障,天然 災害,蓄意破壞 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (664, 'single', '關於「唯讀檔案」之特性，下列何者錯誤？', '能變更其內容,用DIR 命 令可看到其檔案名稱,不可用DEL 刪除,能看到其內容 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (665, 'single', '下列哪一項是區塊鏈用來達到認證的機制？', '電子憑證,共識決,密碼,Kerberos 認證機制 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (666, 'single', '為了防止因資料安全疏失所帶來的災害，一般可將資訊安全概分為下列哪 四類？', '實體安全，網路安全，病毒安全，系統安全,實體安全，法律 安全，程式安全，系統安全,實體安全，資料安全，人員安全，電話安全,實體安全，資料安全，程式安全，系統安全 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (667, 'single', '資訊安全的性質為何？', '既不是技術問題，也不是管理問題,純屬技術 問題，無關管理問題,純屬管理問題，無關技術問題,不但是技術問 題，且是管理問題 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (668, 'single', '一般資訊中心為確保電腦作業而採取各種防護的措施，而防護的項目有四 項，下列哪一項不在這四項之內？', '實體,資料,系統,上機紀錄 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (669, 'single', '有關「電腦安全防護的措施」之敘述，下列哪一項是同時針對「實體」及 「資料」的防護措施？', '人員定期輪調,保留日誌檔,不斷電系統,管 制上機次數與時間 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (670, 'single', '對於「資訊中心的安全防護措施」之敘述，下列何者錯誤？', '資訊中心的 電源設備必有穩壓器及不斷電系統,機房應選用耐火、絕緣、散熱性良好 的材料,四份以上的資料備份，並一起收妥以防遺失,需要資料管制 室，做為原始資料的驗收、輸出報表的整理及其他相關資料保管 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (671, 'single', '關於「資訊中心的安全防護措施」之敘述，下列何者錯誤？', '重要檔案每 天備份四份以上，並分別存放,設置煙及熱度感測器等設備，以防災害發 生,雖是不同部門，資料也可以相互交流，以便相互支援合作，順利完成 工作,加裝穩壓器及不斷電系統（UPS） ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (672, 'single', '主要的硬體安全防護措失，下列何者錯誤？', '虛擬電腦系統（Virtual machine）,記憶體的保護,上線密碼（Login-Password）,核心設計 （Kernel design） ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (673, 'single', '關於「防火牆」之敘述，下列何者錯誤？', '防火牆無法防止內賊對內的侵 害，根據經驗，許多入侵或犯罪行為都是自己人或熟知內部網路佈局的人 做的,防火牆基本上只管制封包的流向，它無法偵測出外界假造的封包， 任何人皆可製造假的來源住址的封包,防火牆無法確保連線的可信度，一 旦連線涉及外界公眾網路，極有可能被竊聽或劫奪，除非連線另行加密保 護,防火牆可以防止病毒的入侵 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (674, 'single', '下列何者不是「數位簽名」的功能之一？', '證明了信的來源,做為信件 分類之用,可檢測信件是否遭竄改,發信人無法否認曾發過信 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (675, 'single', '下列何者不是常見的「Web 安全協定」之一？', '私人通訊技術（PCT）協 定,安全超文字傳輸協定（S-HTTP）,電子佈告欄（BBS）傳輸協定,安全電子交易（SET）協定 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (676, 'single', '下列何者是一個用來存放與管理通訊錄及我們在網路上付費的信用卡資 料，以確保交易時各項資料的儲存或傳送時的隱密性與安全性？', '電子錢 包,商店伺服器,付款轉接站,認證中心 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (677, 'single', '下列何者是網路安全之原則？', '寫下你的密碼,密碼中最好包含字母及 非字母字元,用你名字或帳號當作密碼,用你個人的資料當作密碼 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (678, 'single', '如果一個僱員必須被停職，他的網路存取權應在何時被關閉？', '停職後一 週,停職後二週,給予他停職通知前,不需關閉 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (679, 'single', '離開座位的時候正確的電腦安全習慣是', '啟動已設定密碼之螢幕保護程式,關掉電腦螢幕電源,為節省時間，連線網路下載大量資料,保持開機 狀態，節省重新開機時間 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (680, 'single', '有關於「弱點法則」之敘述，下列何者錯誤？', '舊的弱點攻擊重新發生的 主要原因，多來自組織單位重新安裝佈署機器後未能立即修補,有心人士 利用弱點的入侵攻擊行為，大約只有20%的少部分比率是發生在重要弱點 的頭二個半衰期,安全弱點半衰期指的是一個重要的弱點，每隔一般時間 後，發現有此弱點的系統將會減半,常見的嚴重弱點一年內會被另一個新 發現的弱點取代 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (681, 'single', '下列何者不是使用即時通訊軟體應有的正確態度？', '不輕易開啟接收的檔 案,不任意安裝來路不明的程式,對不認識的網友開啟視訊功能以示友 好,不輕信陌生網友的話 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (682, 'single', '「Cross-site scripting 攻擊」無法達到下列何種行為？', '強迫瀏覽者轉址,取得網站伺服器控制權,偷取瀏覽者cookie,騙取瀏覽者輸入資料 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (683, 'single', '對於「零時差攻擊（zero-day attack）」之敘述，下列何者正確？', '在軟 體弱點被發現，但尚未有任何修補方法前所出現的對應攻擊行為,在午夜 12 點（零點）發動攻擊的一種病毒行為,弱點掃描與攻擊發生在同一天 的一種攻擊行為,攻擊與修補發生在同一天的一種網路事件 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (684, 'single', '「資料外洩」是破壞了「資訊安全」中的哪一面向？', '可用性 （Availability）,機密性（Confidentiality）,不可否認性（Non- repudiation）,完整性（Integrity） ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (685, 'single', '不使用未經驗證合格之電腦屬於哪一種風險對策？', '破解,降低,接受,迴避 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (686, 'single', '下列敘述何者正確？', '資訊安全的問題人人都應該注意,我的電腦中沒 有重要資料所以不需注意資訊安全的問題,為了怕忘記，所以密碼愈簡單 易記愈好,網路上的免費軟體應多多下載，以擴充電腦的功能 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (687, 'single', '有關於「弱點」之敘述，下列何者錯誤？', '弱點是一種使用者操作上的錯 誤或瑕疵,弱點存在與暴露可能導致有心人士利用作為入侵途徑,弱點 可能導致程式運作出現非預期結果而造成程式效能上的損失或進一步的權 益損害,管理員若未能即時取得弱點資訊與修正檔將導致被入侵的可能性 增加 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (688, 'single', '「資訊安全」的三個面向不包含下列何者？', '機密性（Confidentiality）,可用性（Availability）,不可否認性（Non-repudiation）,完整性 （Integrity） ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (689, 'single', '可過濾、監視網路上的封包與通聯狀況，達到保護電腦的軟體為何？', '防 毒軟體,防火牆,瀏覽器,即時通 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (690, 'single', '資安事件的防護機制可採取下列哪一方式？', 'DIY（執行、檢查、回報）,TINA（測試、保險、協商、執行）,PIRR（預防、保險、回應、復 原）,PDRR（預防、偵測、回應、復原） ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (691, 'single', '社交工程造成資訊安全極大威脅的原因在於下列何者？', '破壞資訊服務可 用性，使企業服務中斷,隱匿性高，不易追查惡意者,惡意人士不需要 具備頂尖的電腦專業技術即可輕易地避過了企業的軟硬體安全防護,利用 通訊埠掃描（Port Scan）方式，無從防範 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (692, 'single', '政府機關公務內部網路系統資訊遭竊的最主要威脅來自下列何者？', '社交 工程與位址假造,社交工程與零時差攻擊結合,國際恐怖分子與國內政 治狂熱者,實體安全防護不佳 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (693, 'single', '遇到不明人士要進入管制區域的最好處理方式是下列何者？', '因為是來往 洽公人員，所以沒關係,可能是長官巡視，就幫他開門,立即阻止其進 入，通知檢警調單位協助處理,瞭解其來意，通知相關人員陪同進入 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (694, 'single', '下列何者不是「虛擬私人網路（VPN，Virtual Private Network）」採用的 技術原理？', '穿隧技術,加解密技術,備援技術,使用者與設備身分鑑 別技術 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (695, 'single', '如何最有效建立員工資訊安全意識？', '從工作中建立,懲罰,獎勵,定 期提醒與教育訓練 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (696, 'single', '對需考慮資訊安全的公司或單位，下列何者是屬於進出公司必要進行安全 管制的可攜式設備或可攜式儲存媒體？', '手機、隨身碟、平板電腦、投影 機,手機、隨身碟、筆記型電腦、投影機,手機、隨身碟、平板電腦、 筆記型電腦,隨身碟、平板電腦、筆記型電腦、投影機 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (697, 'single', '對於使用可攜式儲存媒體（光碟或隨身碟）的風險描述，下列何者有誤？', '只要不開啟其中內容，就算已連接到電腦上，也是安全的,容易將電腦 病毒、木馬程式傳回自己或其他的電腦,媒體容易遺失,儲存其中的資 料易遭竊取或竄改 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (698, 'single', '下列何者不是防範電子郵件社交工程的有效措施？', '安裝防毒軟體，確實 更新病毒碼,確認信件是否來自來往單位,取消信件預覽功能,制訂企 業資訊安全政策，禁止使用非法郵件軟體 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (699, 'single', '下列哪一項攻擊無法藉由過濾輸入參數來防禦？', 'Directory listing,SQL injection,Cross site scripting,Command injection ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (700, 'single', '某企業為因應潮流並提升其企業對資訊系統的安全防護，決定導入最新的 ISMS 國際驗證標準，請問它應該導入的驗證標準是什麼？', 'ISO/IEC 17799:2005,ISO/IEC 27001,BS7799 part 1,ISO 9001:2000 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (701, 'single', '下列對安裝作業系統時的安全考量，何者為不適當的處理？', '作業系統軟 體的合法性,作業系統修補套件的安裝處理,作業系統軟體的破解版備 份,預設環境設定中不安全因素的修改檢驗 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (702, 'single', '下列何者是好的電子郵件使用習慣？', '收到信件趕快打開或執行郵件中的 附檔,利用電子郵件傳遞機密資料,使用電子郵件大量寄發廣告信,不 輕易將自己的電子郵件位址公佈與網站中 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (703, 'single', '「社交工程（social engineering）」是一種利用下列何種特性所發展出來 的攻擊手法？', '通訊協定的弱點,人際互動與人性弱點,作業系統的漏 洞,違反資料機密性（Confidentiality）的要求 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (704, 'single', '透過網路入侵別人的電腦，破壞或竊取資料謀利者，一般稱之為何？', '人 客,海客,駭客,害客 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (705, 'single', '下列敘述何者錯誤？', '跨站指令碼不但影響伺服主機，甚至會導致瀏覽者 受害,SQL injection 是一種攻擊網站資料庫的手法,跨目錄存取是因為 程式撰寫不良,存放網頁應用程式的系統安裝最新系統修補程式後，便不 會存有弱點 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (706, 'single', '在ISMS 的稽核報告中，不滿足標準條款規定的，稱之為何？', '不符合事 項（non-conformance）,缺失事項（defect）,不足事項（deficient）,建議事項（recommend） ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (707, 'single', '下列何者不是「資料隱碼攻擊（SQL injection）」的特性？', '為使用者而 非開發程式者造成,造成資料庫資料遭竄改或外洩,主要原因為程式缺 乏輸入驗證,可跳過驗證並入侵系統 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (708, 'single', '系統安全漏洞發生的主要原因為何？', '硬體速度過慢,系統程式開發之 疏失,電腦儲存空間不足,電源供應不穩定 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (709, 'single', '資訊安全是必須保護資訊資產的哪些特性？', '機密性、方便性、可讀性,完整性、可攜性、機動性,機動性、可用性、完整性,可用性、完整 性、機密性 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (710, 'single', '在公共環境中使用自己的筆記型電腦若偵測到可用的無線網路時應該如何 處置？', '馬上連線使用,確認自己是否有使用權並瞭解其安全保護機制 再決定是否使用,無線網路不易監聽所以可以放心傳送重要的資訊,只 要確認自己的筆記型電腦的資料傳輸是經過加密的，就可放心使用 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (711, 'single', '有關「防火牆」之敘述，下列何者正確？', '企業使用，個人電腦中無法使 用,有了防火牆，電腦即可得到絕對的安全防護,防火牆如果沒有合適 的設定則無法發揮過濾阻擋功效,防火牆可以修補系統的安全漏洞 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (712, 'single', '下列哪一項不屬於「社交工程攻擊」手法？', '郵件仿冒或偽裝,針對帳 號密碼採行字典攻擊法,網路釣魚,電話詐騙個人資訊 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (713, 'single', '下列哪一項區塊鏈技術之敘述錯誤？', '使用最少的資源來達到最安全的效 果,仰賴多台網路主機來協助產生區塊,區塊是以被雜的加密和雜湊演 算法來執行,每一項交易都需要進行資料認證 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (714, 'single', '從資訊安全的角度而言，下列哪一種作法是不適當的？', '轉寄信件時將前 寄件人的收件名單引入信件中,不在網站中任意留下自己的私密資料,不使用電子郵件傳遞機密文件,使用防毒軟體保護自己的電腦 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (715, 'single', '下列何者不是資訊安全要維護的資訊特性？', '保密性,完整性,可用性,可讀性 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (716, 'single', '下列何者不是資訊安全威脅的攻擊目的？', '侵入,竄改或否認,阻斷服 務,獲得歸屬感 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (717, 'single', '下列何者不是資料隱碼攻擊（SQL Injection）的防禦方法？', '對字串過濾 並限制長度,加強資料庫權限管理，不以系統管理員帳號連結資料庫,對使用者隱藏資料庫管理系統回傳的錯誤訊息，以免攻擊者獲得有用資訊,在程式碼中標示註解 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (718, 'single', '下列何者不是通關密碼的破解方法？', '窮舉攻擊,字典攻擊,彩虹表攻 擊,RGB 攻擊 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (719, 'single', '下列何者不可能是後門攻擊的後門產生途徑？', '軟體開發者忘記移除的維 護後門,攻擊者植入的後門,管理人員安裝的遠端控制軟體,軟體開發 者打開的客廳後門 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (720, 'single', '下列何者不是入侵偵測與防禦系統（IDPS）的安全事件偵測方法？', '比 對惡意攻擊的特徵,分析異常的網路活動,偵測異常的通訊協定狀態,確認使用者的權限 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (721, 'single', '下列何者不是網路安全漏洞的可能來源？', '軟體的瑕疵,使用者的不良 使用習慣,多種軟/硬體結合而產生的問題,圍牆與機房之間的距離很 大 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (722, 'single', '下列何種作法無法強化網頁伺服器的安全？', '伺服器只安裝必要的功能模 組,封鎖不良使用者的IP,使用防火牆使其只能於組織內部存取,組織 的所有電腦均使用Intel CPU ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (723, 'single', '下列關於實體安全防禦措施的說明，何者不正確？', '在事前，實體安全防 禦措施要達到嚇阻效果，讓攻擊者知難而退,在事件發生中，實體安全防 禦措施應能儘量拖延入侵者的行動,在偵測到入侵事件後，實體安全防禦 措施須能儘量記錄犯罪證據，以為事後追查與起訴的憑據,在事件發生 中，實體安全防禦措施要達到嚇阻效果，讓攻擊者知難而退 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (724, 'single', '企業的防火牆通常不應該拒絶下列哪種封包？', '外部進入的telnet 封包,外部進入但位址標示為內部的封包,外部進入的HTTP 封包,外部進 入且目的位址是防火牆的封包 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (725, 'single', '下列何者不是發生電腦系統記憶體滲漏（Memory Leak）的可能肇因？', '作業系統有錯誤,應用程式有錯誤,網路卡故障,驅動程式有錯誤 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (726, 'single', '下列何種協定可以讓組織在區域網路內使用私人IP，而在公開網路上共用 一個外部IP？', 'VLAN,DMZ,VPN,NAT ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (727, 'single', '下列何者最能確保通訊資料的安全性？', '壓縮資料,備份資料,分割資 料,加密資料 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (728, 'single', '公開金鑰密碼系統中，要讓資料傳送時以亂碼呈現，並且傳送者無法否認 其傳送行為，需要使用哪兩個金鑰同時加密才能達成？', '傳送者及接收者 的私鑰,傳送者及接收者的公鑰,接收者的私鑰及傳送者的公鑰,接收 者的公鑰及傳送者的私鑰 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (729, 'single', '下列何者可以在使用者不知情的情況下收集密碼？', '按鍵記錄器,鍵盤 驅動程式,藍芽接收器,滑鼠驅動程式 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (730, 'single', '包含可辨識單字的密碼，容易受到哪種類型的攻擊？', 'DDoS 攻擊,字典 攻擊,雜湊攻擊,回放攻擊 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (731, 'single', '如果您是某地方法院的資訊管理師，某位自稱王書記官的使用者來電要求 變更密碼，您應該優先做何種處置？', '提供新的密碼,驗證使用者的身 分,替使用者更換電腦,中斷使用者電腦的網路連線 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (732, 'single', '入侵偵測方法中，相較於特徵偵測（Signature-Based Detection）及異常偵 測（Anomaly-Based Detection）的好處為何？', '偵測比較準確,可以偵 測未知的威脅,速度較快,可以做到即時偵測 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (733, 'single', '下列何者不是加密方法？', 'AES,DES,NAS,RSA ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (734, 'single', '下列哪種方法可以有效降低入侵偵測系統（IDS）的誤判機率？', '優化通 知的優先順序,將已知有風險者記入黑名單，已知安全者記入白名單,更多元的警示方式,修改IDS，讓它更符合組織的安全政策 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (735, 'single', '相較於特徵比對法，下列何者是使用探索法防毒軟體的優點？', '對於識別 已知惡意程式相當有效,擅長偵測已知病毒的變形、變種,可有效降低 誤殺率,可以偵測全新的病毒 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (736, 'single', '下列何者沒有Redundancy？', 'RAID 0,RAID 1,RAID 10,RAID 3 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (737, 'single', '下列何種駭客手法是在DNS 伺服器插入錯誤訊息，藉以將網站訪問者引導 到其它網站？', 'DNS-Poisoning,DNS-Hijacking,DNS-Cracking,DNS-Injection ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (738, 'single', '下列何種措施有害於資訊安全？', '使用者的使用權限均相同,定期保存 日誌檔,設置密碼,資料備份 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (739, 'single', 'Windows 作業系統不可以替下列何者指定NTFS 權限？', '副檔名,檔案,資料夾,子資料夾 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (740, 'single', '下列何者不是企業常用來防止駭客入侵內部網路的措施？', '定期更換使用 者密碼,電腦加裝掃毒軟體且定期更新版本,定期進行資料備份,在內 部網路與外部網路間建構防火牆 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (741, 'single', '有關網路防火牆（Firewall）之敘述，下列何者正確？', '用來防止駭客入 侵的防護機制,壓縮與解壓縮技術,資料加解密技術,電子商務的線上 付款機制 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (742, 'single', '下列敘述何者錯誤？', '販賣盜版軟體是違法的行為,電腦病毒不可能經 由光碟片來感染,使用並定期更新防毒軟體可以降低感染電腦病毒的機會,惡意製作並散播電腦病毒是違法的行為 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (743, 'single', '有關數位憑證之敘述，下列何者正確？', '只能由警察局核發,可用來辨 識認證對象的身分,自然人憑證不屬於數位憑證,自然人憑證只有公司 行號能申請，個人無法申請 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (744, 'single', '使用防火牆有助於防範下列何種駭客的攻擊？', '零時差攻擊,網路釣魚,阻斷服務攻擊,邏輯炸彈 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (745, 'single', '駭客發現軟體的安全漏洞後，趁廠商尚未進行修補時，立刻進行攻擊，這 種手法稱為？', '零時差攻擊,BotNet 攻擊,木馬攻擊,DoS 攻擊 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (746, 'single', '駭客遙控大量的「殭屍電腦」來濫發垃圾郵件、竊取他人個資等不法行 為，這種手法稱為？', '木馬攻擊,BotNet 攻擊,零時差攻擊,網路釣魚 攻擊 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (747, 'single', '下列何種觀念敘述不正確？', '使用防毒軟體仍需經常更新病毒碼,不可 隨意開啟不明來源電子郵件的附加檔案,重要資料燒錄於光碟儲存，可避 免受病毒感染及破壞,將資料備份於不同的資料夾內，可確保資料安 全 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (748, 'single', '下列何種攻擊針對特定主機不斷且持續發出大量封包，藉以癱瘓系統？', '木馬攻擊,網路蠕蟲攻擊,阻斷服務（DoS）攻擊,隱私竊取 ', '2', '');
